// @ts-check
/** @typedef {import('../../InvocationContext.js').InvocationContext} InvocationContext */

import { Command } from '../../../utils/Command.js'
import { CommandType } from '../../../utils/CommandType.js'
import { RuntimeName } from '../../../utils/RuntimeName.js'
import { handleResultWithAction } from './TypeParsingUtils.js'

const UNIX_EPOCH_TICKS = 621_355_968_000_000_000

/**
 * @param {InvocationContext} invocationContext
 * @returns {Date}
 */
export function parseDateTime(invocationContext) {
    const result = invocationContext.getInstanceField('Ticks').execute()
    return handleResultWithAction(result, (/** @type {any} */ ticks) => {
        if (ticks == null) throw new Error('Ticks returned null')
        const epochMilli = (Number(ticks) - UNIX_EPOCH_TICKS) / 10_000
        return new Date(epochMilli)
    })
}

/**
 * @param {InvocationContext} invocationContext
 * @returns {Date}
 */
export function parseDateTimeOffset(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('ToString', 'o').execute()
    return handleResultWithAction(result, (/** @type {any} */ iso) => new Date(String(iso)))
}

/**
 * @param {InvocationContext} invocationContext
 * @returns {string}
 */
export function parseGuid(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('ToString').execute()
    return handleResultWithAction(result, (/** @type {any} */ val) => String(val))
}

/** Inbound: .NET Core result type string → JavaScript object */
export const NetcoreTypeParsingFunctions = new Map(/** @type {[string, (invocationContext: InvocationContext) => unknown][]} */ ([
    ['System.DateTime', parseDateTime],
    ['System.DateTimeOffset', parseDateTimeOffset],
    ['System.Guid', parseGuid],
]))

/**
 * Outbound: JavaScript object → Command graph targeting the .NET Core runtime
 * @type {Map<Function, (value: any) => Command>}
 */
export const NetcoreParsingArgument = new Map([
    [Date, (/** @type {Date} */ value) => new Command(RuntimeName.Netcore, CommandType.InvokeStaticMethod, [
        new Command(RuntimeName.Netcore, CommandType.GetType, ['System.DateTime']),
        'Parse',
        value.toISOString(),
    ])],
])
